                    writer.WriteString("start_on", projectRequest.StartOnOption.Value!.Value.ToString(StartOnFormat));
                else
                    writer.WriteNull("start_on");

            var defaultAccessLevelRawValue = ProjectRequest.DefaultAccessLevelEnumToJsonValue(projectRequest.DefaultAccessLevelOption.Value!.Value);
            writer.WriteString("default_access_level", defaultAccessLevelRawValue);
            var minimumAccessLevelForCustomizationRawValue = ProjectRequest.MinimumAccessLevelForCustomizationEnumToJsonValue(projectRequest.MinimumAccessLevelForCustomizationOption.Value!.Value);
            writer.WriteString("minimum_access_level_for_customization", minimumAccessLevelForCustomizationRawValue);
            var minimumAccessLevelForSharingRawValue = ProjectRequest.MinimumAccessLevelForSharingEnumToJsonValue(projectRequest.MinimumAccessLevelForSharingOption.Value!.Value);
            writer.WriteString("minimum_access_level_for_sharing", minimumAccessLevelForSharingRawValue);
            if (projectRequest.CustomFieldsOption.IsSet)
            {
                writer.WritePropertyName("custom_fields");
                JsonSerializer.Serialize(writer, projectRequest.CustomFields, jsonSerializerOptions);
            }
            if (projectRequest.FollowersOption.IsSet)
                writer.WriteString("followers", projectRequest.Followers);

            if (projectRequest.OwnerOption.IsSet)
                if (projectRequest.OwnerOption.Value != null)
                    writer.WriteString("owner", projectRequest.Owner);
                else
                    writer.WriteNull("owner");

            if (projectRequest.TeamOption.IsSet)
                writer.WriteString("team", projectRequest.Team);

            if (projectRequest.WorkspaceOption.IsSet)
                writer.WriteString("workspace", projectRequest.Workspace);
        }
    }
}
